    private void heapifyUp(int pos) {
        int parentPos = pos / 2;
        if (pos > 1 && Heap[pos] > Heap[parentPos]) {
            int tmp;
            tmp = Heap[pos];
            Heap[pos] = Heap[parentPos];
            Heap[parentPos] = tmp;
            heapifyUp(parentPos);
        }
    }

    public void insert(int element) {
        Heap[++size] = element;
        heapifyUp(size);
    }
}

