const int INF = 1e9;

void dijkstra(int start, std::vector<std::vector<std::pair<int, int>>>& graph) {
    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, std::greater<>> pq;
    std::vector<int> distance(graph.size(), INF);
    pq.push({0, start});
    distance[start] = 0;
    while (!pq.empty()) {
        int current_distance = pq.top().first;
        int current_node = pq.top().second;
        pq.pop();
        if (current_distance > distance[current_node]) continue;
        for (auto& edge : graph[current_node]) {
            int neighbor = edge.first;
            int weight = edge.second;
            if (current_distance + weight < distance[neighbor]) {
                distance[neighbor] = current_distance + weight;
                pq.push({distance[neighbor], neighbor});
            }
        }
    }
    for (int i = 0; i < distance.size(); ++i)
        std::cout << "Distance to node " << i << " is " << distance[i] << std::endl;
}

